mapper.select:
SELECT t.tender_version_id, t.project_id, p.project_name, t.lot_id, l.lot_code, l.lot_name, t.version_no, t.version_type, t.status, t.current_flag, t.parent_version_id, t.effective_time, t.publish_time, t.summary, t.remark, t.version, t.create_time, t.update_time FROM t_bid_tender_version t INNER JOIN t_bid_project p ON p.project_id = t.project_id INNER JOIN t_bid_lot l ON l.lot_id = t.lot_id
t.deleted_flag = #{queryForm.deletedFlag} AND p.deleted_flag = 0 AND l.deleted_flag = 0
AND ( p.project_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_code LIKE CONCAT('%', #{queryForm.keyword}, '%') OR t.summary LIKE CONCAT('%', #{queryForm.keyword}, '%') )
AND t.project_id = #{queryForm.projectId}
AND t.lot_id = #{queryForm.lotId}
AND t.version_type = #{queryForm.versionType}
AND t.status = #{queryForm.status}
ORDER BY t.create_time DESC, t.tender_version_id DESC
